import { useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { toast } from 'sonner';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { ApiError } from '@/lib/api';
import { useDataSourcesQuery, type DataSourceEntry } from '@/routes/data-sources/queries';
import {
  MIGRATION_MODE,
  MIGRATION_MODE_LABEL,
  useCreateMigrationJob,
  type CreateMigrationJobPayload,
  type MigrationModeId,
} from '@/routes/migration-history/queries';

const SCHEMA = z.object({
  name: z.string().trim().min(1, 'Name is required').max(200),
  description: z.string().trim().min(1, 'Description is required').max(1000),
  dataSourceId: z.number().int().min(1, 'Pick a source data source'),
  queryText: z.string().trim().min(1, 'Source SQL is required'),
  destinationDataSourceId: z.number().int().min(1, 'Pick a destination data source'),
  destinationTable: z.string().trim().min(1, 'Destination table is required').max(200),
  mode: z.number().int().min(1).max(3),
  isEnabled: z.boolean(),
  schedule: z.string(),
  maxRetries: z.number().int().min(0).max(10),
  timeoutMinutes: z.number().int().min(1).max(1440),
  validateBeforeExecution: z.boolean(),
  transformationScript: z.string(),
});

type FormValues = z.infer<typeof SCHEMA>;

const DEFAULTS: FormValues = {
  name: '',
  description: '',
  dataSourceId: 0,
  queryText: '',
  destinationDataSourceId: 0,
  destinationTable: '',
  mode: MIGRATION_MODE.Insert,
  isEnabled: true,
  schedule: '',
  maxRetries: 3,
  timeoutMinutes: 30,
  validateBeforeExecution: true,
  transformationScript: '',
};

const MODE_OPTIONS: ReadonlyArray<{ value: MigrationModeId; label: string }> = [
  { value: MIGRATION_MODE.Insert, label: MIGRATION_MODE_LABEL[MIGRATION_MODE.Insert] },
  { value: MIGRATION_MODE.Upsert, label: MIGRATION_MODE_LABEL[MIGRATION_MODE.Upsert] },
  { value: MIGRATION_MODE.Truncate, label: MIGRATION_MODE_LABEL[MIGRATION_MODE.Truncate] },
];

export default function NewMigrationJobPage() {
  const navigate = useNavigate();
  const dataSourcesQuery = useDataSourcesQuery();
  const createMutation = useCreateMigrationJob();

  const dbSources: DataSourceEntry[] = useMemo(
    () => (dataSourcesQuery.data?.entries ?? []).filter(x => x.databaseEngineType !== null),
    [dataSourcesQuery.data],
  );

  const {
    register,
    handleSubmit,
    formState: { errors, isSubmitting },
  } = useForm<FormValues>({
    resolver: zodResolver(SCHEMA),
    defaultValues: DEFAULTS,
    mode: 'onTouched',
  });

  const onSubmit = handleSubmit(async v => {
    const payload: CreateMigrationJobPayload = {
      name: v.name.trim(),
      description: v.description.trim(),
      dataSourceId: v.dataSourceId,
      queryText: v.queryText,
      destinationDataSourceId: v.destinationDataSourceId,
      destinationTable: v.destinationTable.trim(),
      mode: v.mode as MigrationModeId,
      isEnabled: v.isEnabled,
      schedule: v.schedule.trim() === '' ? null : v.schedule.trim(),
      maxRetries: v.maxRetries,
      timeoutMinutes: v.timeoutMinutes,
      validateBeforeExecution: v.validateBeforeExecution,
      transformationScript: v.transformationScript.trim() === '' ? null : v.transformationScript,
    };
    try {
      const result = await createMutation.mutateAsync(payload);
      if (!result.success) {
        toast.error(result.errorMessage ?? 'Failed to create migration job.');
        return;
      }
      toast.success('Migration job created.');
      navigate(`/migration-jobs/${result.migrationJobId}`);
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Request failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  });

  return (
    <div className="page">
      <PageHeader
        title="New migration job"
        sub={
          <span className="muted">
            <Link to="/migration-jobs" className="muted">Migration jobs</Link>
            <span style={{ margin: '0 6px' }}>/</span>
            New
          </span>
        }
        actions={
          <Link className="btn" to="/migration-jobs">Cancel</Link>
        }
      />

      {!dataSourcesQuery.isLoading && dbSources.length < 2 && (
        <div className="card" style={{ marginBottom: 16 }}>
          <div className="card__body">
            <span className="muted">
              Migration jobs need at least two database data sources (source and destination).{' '}
              <Link to="/data-sources">Configure data sources</Link>.
            </span>
          </div>
        </div>
      )}

      <form onSubmit={onSubmit} noValidate>
        <Section icon={<Icon.Layers size={14} />} title="Basics">
          <Field label="Job name" required error={errors.name?.message}>
            <input
              type="text"
              className={`q-input${errors.name ? ' q-input--error' : ''}`}
              {...register('name')}
            />
          </Field>
          <Field label="Description" required error={errors.description?.message}>
            <textarea
              rows={3}
              className={`q-input${errors.description ? ' q-input--error' : ''}`}
              {...register('description')}
            />
          </Field>
        </Section>

        <Section icon={<Icon.Database size={14} />} title="Source">
          <Field label="Source data source" required error={errors.dataSourceId?.message}>
            <select
              className={`q-input${errors.dataSourceId ? ' q-input--error' : ''}`}
              {...register('dataSourceId', { setValueAs: v => v === '' || v == null ? 0 : Number(v) })}
            >
              <option value={0}>— Select source —</option>
              {dbSources.map(ds => (
                <option key={ds.id} value={ds.id}>{ds.name} ({ds.databaseEngineType})</option>
              ))}
            </select>
          </Field>
          <Field label="Source SQL" required error={errors.queryText?.message} help="Use :param placeholders for dynamic values.">
            <textarea
              rows={6}
              className={`q-input mono${errors.queryText ? ' q-input--error' : ''}`}
              placeholder="SELECT * FROM source_table WHERE updated_at >= :since"
              {...register('queryText')}
            />
          </Field>
        </Section>

        <Section icon={<Icon.ArrowsLR size={14} />} title="Destination">
          <Field label="Destination data source" required error={errors.destinationDataSourceId?.message}>
            <select
              className={`q-input${errors.destinationDataSourceId ? ' q-input--error' : ''}`}
              {...register('destinationDataSourceId', { setValueAs: v => v === '' || v == null ? 0 : Number(v) })}
            >
              <option value={0}>— Select destination —</option>
              {dbSources.map(ds => (
                <option key={ds.id} value={ds.id}>{ds.name} ({ds.databaseEngineType})</option>
              ))}
            </select>
          </Field>
          <Field label="Destination table" required error={errors.destinationTable?.message}>
            <input
              type="text"
              className={`q-input mono${errors.destinationTable ? ' q-input--error' : ''}`}
              placeholder="public.target_table"
              {...register('destinationTable')}
            />
          </Field>
          <Field label="Migration mode" required>
            <select className="q-input" {...register('mode', { valueAsNumber: true })}>
              {MODE_OPTIONS.map(o => (
                <option key={o.value} value={o.value}>{o.label}</option>
              ))}
            </select>
          </Field>
        </Section>

        <Section icon={<Icon.Refresh size={14} />} title="Schedule & options">
          <Field label="Cron schedule" help="Standard 5-field cron. Leave empty for manual-only execution.">
            <input
              type="text"
              className="q-input mono"
              placeholder="0 2 * * *"
              {...register('schedule')}
            />
          </Field>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
            <Field label="Max retries">
              <input
                type="number"
                className="q-input"
                min={0}
                max={10}
                {...register('maxRetries', { valueAsNumber: true })}
              />
            </Field>
            <Field label="Timeout (minutes)">
              <input
                type="number"
                className="q-input"
                min={1}
                max={1440}
                {...register('timeoutMinutes', { valueAsNumber: true })}
              />
            </Field>
          </div>
          <div style={{ display: 'grid', gap: 6, marginTop: 6 }}>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" {...register('isEnabled')} />
              <span>Enable migration job</span>
            </label>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" {...register('validateBeforeExecution')} />
              <span>Validate query before execution</span>
            </label>
          </div>
          <Field label="Transformation script (optional)">
            <textarea
              rows={3}
              className="q-input mono"
              placeholder="Use result1, result2 syntax for cross-step transforms"
              {...register('transformationScript')}
            />
          </Field>
        </Section>

        <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
          <Link className="btn" to="/migration-jobs">Cancel</Link>
          <button
            type="submit"
            className="btn btn--primary"
            disabled={isSubmitting || createMutation.isPending || dbSources.length < 2}
          >
            {createMutation.isPending ? 'Creating…' : 'Create migration job'}
          </button>
        </div>
      </form>
    </div>
  );
}

function Section({ icon, title, children }: { icon: React.ReactNode; title: string; children: React.ReactNode }) {
  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card__body">
        <h3 className="card__title" style={{ margin: '0 0 12px', display: 'flex', alignItems: 'center', gap: 6 }}>
          {icon} {title}
        </h3>
        {children}
      </div>
    </div>
  );
}

function Field({ label, required, error, help, children }: { label: string; required?: boolean; error?: string; help?: string; children: React.ReactNode }) {
  return (
    <div className="q-field" style={{ marginTop: 12 }}>
      <label className="q-label">
        {label}{required && <span className="q-label__req">*</span>}
      </label>
      {children}
      {help && <div className="q-help">{help}</div>}
      {error && <div className="q-error">{error}</div>}
    </div>
  );
}
